import request from 'supertest';
import app from '../../backend/app';
import { createConnection, getConnection } from 'typeorm';
import { User } from '../../backend/entities/User';

beforeAll(async () => {
  await createConnection();
});
afterAll(async () => {
  await getConnection().close();
});

describe('Auth Integration Tests', () => {
  test('should register a new user', async () => {
    const response = await request(app)
      .post('/auth/register')
      .send({ email: 'test@example.com', password: 'password123' });
    expect(response.status).toBe(201);
    expect(response.body.email).toBe('test@example.com');
  });

  test('should login an existing user', async () => {
    await request(app)
      .post('/auth/register')
      .send({ email: 'test2@example.com', password: 'password123' });
    const response = await request(app)
      .post('/auth/login')
      .send({ email: 'test2@example.com', password: 'password123' });
    expect(response.status).toBe(200);
    expect(response.body.token).toBeDefined();
  });

  test('should not login with incorrect password', async () => {
    await request(app)
      .post('/auth/register')
      .send({ email: 'test3@example.com', password: 'password123' });
    const response = await request(app)
      .post('/auth/login')
      .send({ email: 'test3@example.com', password: 'wrongpassword' });
    expect(response.status).toBe(401);
  });
});

import request from 'supertest';
import app from '../../backend/app';
import { createConnection, getConnection } from 'typeorm';
import { User } from '../../backend/entities/User';
import { Workspace } from '../../backend/entities/Workspace';

beforeAll(async () => {
  await createConnection();
});
afterAll(async () => {
  await getConnection().close();
});

describe('Workspace Integration Tests', () => {
  let token: string;
  let userId: number;

  beforeAll(async () => {
    const response = await request(app)
      .post('/auth/register')
      .send({ email: 'test@example.com', password: 'password123' });
    token = response.body.token;
    const user = await User.findOne({ where: { email: 'test@example.com' } });
    userId = user.id;
  });

  test('should create a new workspace', async () => {
    const response = await request(app)
      .post('/workspaces')
      .set('Authorization', `Bearer ${token}`)
      .send({ name: 'Test Workspace' });
    expect(response.status).toBe(201);
    expect(response.body.name).toBe('Test Workspace');
    expect(response.body.ownerId).toBe(userId);
  });

  test('should get workspaces for a user', async () => {
    await request(app)
      .post('/workspaces')
      .set('Authorization', `Bearer ${token}`)
      .send({ name: 'Another Workspace' });
    const response = await request(app)
      .get('/workspaces')
      .set('Authorization', `Bearer ${token}`);
    expect(response.status).toBe(200);
    expect(response.body.length).toBe(2);
  });
});

import request from 'supertest';
import app from '../../backend/app';
import { createConnection, getConnection } from 'typeorm';
import { User } from '../../backend/entities/User';
import { Workspace } from '../../backend/entities/Workspace';
import { Task } from '../../backend/entities/Task';

beforeAll(async () => {
  await createConnection();
});
afterAll(async () => {
  await getConnection().close();
});

describe('Task Integration Tests', () => {
  let token: string;
  let workspaceId: number;

  beforeAll(async () => {
    const response = await request(app)
      .post('/auth/register')
      .send({ email: 'test@example.com', password: 'password123' });
    token = response.body.token;
    const workspaceResponse = await request(app)
      .post('/workspaces')
      .set('Authorization', `Bearer ${token}`)
      .send({ name: 'Test Workspace' });
    workspaceId = workspaceResponse.body.id;
  });

  test('should create a new task', async () => {
    const response = await request(app)
      .post(`/workspaces/${workspaceId}/tasks`)
      .set('Authorization', `Bearer ${token}`)
      .send({ title: 'Test Task', description: 'This is a test task' });
    expect(response.status).toBe(201);
    expect(response.body.title).toBe('Test Task');
    expect(response.body.description).toBe('This is a test task');
  });

  test('should update a task', async () => {
    const createResponse = await request(app)
      .post(`/workspaces/${workspaceId}/tasks`)
      .set('Authorization', `Bearer ${token}`)
      .send({ title: 'Update Test Task', description: 'This is an updated test task' });
    const taskId = createResponse.body.id;
    const updateResponse = await request(app)
      .put(`/tasks/${taskId}`)
      .set('Authorization', `Bearer ${token}`)
      .send({ title: 'Updated Task Title' });
    expect(updateResponse.status).toBe(200);
    expect(updateResponse.body.title).toBe('Updated Task Title');
  });

  test('should delete a task', async () => {
    const createResponse = await request(app)
      .post(`/workspaces/${workspaceId}/tasks`)
      .set('Authorization', `Bearer ${token}`)
      .send({ title: 'Delete Test Task', description: 'This is a test task for deletion' });
    const taskId = createResponse.body.id;
    const deleteResponse = await request(app)
      .delete(`/tasks/${taskId}`)
      .set('Authorization', `Bearer ${token}`);
    expect(deleteResponse.status).toBe(204);
    const getResponse = await request(app)
      .get(`/tasks/${taskId}`)
      .set('Authorization', `Bearer ${token}`);
    expect(getResponse.status).toBe(404);
  });
});

import request from 'supertest';
import app from '../../backend/app';
import { createConnection, getConnection } from 'typeorm';
import { User } from '../../backend/entities/User';
import { Notification } from '../../backend/entities/Notification';

beforeAll(async () => {
  await createConnection();
});
afterAll(async () => {
  await getConnection().close();
});

describe('Notification Integration Tests', () => {
  let token: string;
  let userId: number;

  beforeAll(async () => {
    const response = await request(app)
      .post('/auth/register')
      .send({ email: 'test@example.com', password: 'password123' });
    token = response.body.token;
    const user = await User.findOne({ where: { email: 'test@example.com' } });
    userId = user.id;
  });

  test('should create a new notification', async () => {
    const response = await request(app)
      .post('/notifications')
      .set('Authorization', `Bearer ${token}`)
      .send({ userId, message: 'Test Notification' });
    expect(response.status).toBe(201);
    expect(response.body.message).toBe('Test Notification');
    expect(response.body.userId).toBe(userId);
  });

  test('should mark a notification as read', async () => {
    const createResponse = await request(app)
      .post('/notifications')
      .set('Authorization', `Bearer ${token}`)
      .send({ userId, message: 'Read Test Notification' });
    const notificationId = createResponse.body.id;
    const updateResponse = await request(app)
      .patch(`/notifications/${notificationId}/read`)
      .set('Authorization', `Bearer ${token}`);
    expect(updateResponse.status).toBe(200);
    expect(updateResponse.body.read).toBe(true);
  });

  test('should delete a notification', async () => {
    const createResponse = await request(app)
      .post('/notifications')
      .set('Authorization', `Bearer ${token}`)
      .send({ userId, message: 'Delete Test Notification' });
    const notificationId = createResponse.body.id;
    const deleteResponse = await request(app)
      .delete(`/notifications/${notificationId}`)
      .set('Authorization', `Bearer ${token}`);
    expect(deleteResponse.status).toBe(204);
    const getResponse = await request(app)
      .get(`/notifications/${notificationId}`)
      .set('Authorization', `Bearer ${token}`);
    expect(getResponse.status).toBe(404);
  });
});
